import{_ as a,o as s,c as n,a1 as r}from"./chunks/framework.BwhMLafE.js";const h=JSON.parse('{"title":"Included Languages","description":"","frontmatter":{},"headers":[],"relativePath":"languages.md","filePath":"languages.md"}'),i={name:"languages.md"};function l(t,e,o,d,g,u){return s(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="included-languages" tabindex="-1">Included Languages <a class="header-anchor" href="#included-languages" aria-label="Permalink to &quot;Included Languages&quot;">​</a></h1><h2 id="table-of-contents" tabindex="-1">Table of Contents <a class="header-anchor" href="#table-of-contents" aria-label="Permalink to &quot;Table of Contents&quot;">​</a></h2><ul><li><a href="#overview">Overview</a></li><li><a href="#bundled-grammars">Bundled Grammars</a><ul><li><a href="#json-languagesjson">JSON (<code>languages/json</code>)</a></li><li><a href="#json-structured-ast-languagesjson-structured-ast">JSON Structured AST (<code>languages/json-structured-ast</code>)</a></li><li><a href="#augmented-json-languagesaugmented-json">Augmented JSON (<code>languages/augmented-json</code>)</a></li><li><a href="#lisp-languageslisp">Lisp (<code>languages/lisp</code>)</a></li><li><a href="#lua-languageslua">Lua (<code>languages/lua</code>)</a></li><li><a href="#grammar-parser-languagesgalley">Grammar Parser (<code>languages/galley</code>)</a></li></ul></li><li><a href="#choosing-between-ll-and-lr">Choosing Between LL and LR</a></li><li><a href="#building-and-running-included-languages">Building and Running Included Languages</a></li></ul><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Galley ships with several ready-to-use grammar definitions located in the <code>languages/</code> directory. These bundled languages serve both as comprehensive benchmarks for parsing speed and as architectural reference implementations for defining your own grammars.</p><hr><h2 id="bundled-grammars" tabindex="-1">Bundled Grammars <a class="header-anchor" href="#bundled-grammars" aria-label="Permalink to &quot;Bundled Grammars&quot;">​</a></h2><h3 id="json-languages-json" tabindex="-1">JSON (<code>languages/json</code>) <a class="header-anchor" href="#json-languages-json" aria-label="Permalink to &quot;JSON (`languages/json`)&quot;">​</a></h3><p>The standard RFC 8259 JSON implementation used for JSON benchmarking. It supports full recursive object and array structures, floating-point numbers, unicode escape sequences, and string content literals. Its grammar is written with fewer non-terminals so the generated parser has fewer calls and less intermediate AST structure.</p><ul><li><strong>Parser Engines:</strong> Both <code>ll.grm</code> and <code>lr.grm</code> are provided.</li></ul><h3 id="json-structured-ast-languages-json-structured-ast" tabindex="-1">JSON Structured AST (<code>languages/json-structured-ast</code>) <a class="header-anchor" href="#json-structured-ast-languages-json-structured-ast" aria-label="Permalink to &quot;JSON Structured AST (`languages/json-structured-ast`)&quot;">​</a></h3><p>A full RFC 8259 JSON grammar with additional non-terminals for a richer AST shape. It parses the same language as <code>languages/json</code>, but preserves more intermediate structure and therefore has lower benchmark throughput.</p><ul><li><strong>Parser Engines:</strong> Both <code>ll.grm</code> and <code>lr.grm</code> are provided.</li><li><strong>Hooks:</strong> Implements <code>@drop_children</code>, <code>@drop_self</code>, and <code>@replace_with_children</code> in <code>procedures.zig</code> to shape AST generation.</li></ul><h3 id="augmented-json-languages-augmented-json" tabindex="-1">Augmented JSON (<code>languages/augmented-json</code>) <a class="header-anchor" href="#augmented-json-languages-augmented-json" aria-label="Permalink to &quot;Augmented JSON (`languages/augmented-json`)&quot;">​</a></h3><p>An extended JSON variant designed to test extreme recursion depths and stress-test the parser&#39;s stack overflow recovery mechanisms. It introduces special grouping syntax (<code>*(...)</code> and <code>(...)</code>) that allows deeply nested structures without exceeding memory limits.</p><ul><li><strong>Parser Engines:</strong> Both <code>ll.grm</code> and <code>lr.grm</code> are provided.</li><li><strong>Hooks:</strong> Demonstrates advanced reduction hooking and stack management.</li></ul><h3 id="lisp-languages-lisp" tabindex="-1">Lisp (<code>languages/lisp</code>) <a class="header-anchor" href="#lisp-languages-lisp" aria-label="Permalink to &quot;Lisp (`languages/lisp`)&quot;">​</a></h3><p>A Lisp grammar covering lists, symbols, numbers, strings, reader macros, comments, vectors, arrays, and multiple top-level forms.</p><ul><li><strong>Parser Engines:</strong> <code>ll.grm</code> is provided.</li></ul><h3 id="lua-languages-lua" tabindex="-1">Lua (<code>languages/lua</code>) <a class="header-anchor" href="#lua-languages-lua" aria-label="Permalink to &quot;Lua (`languages/lua`)&quot;">​</a></h3><p>A Lua grammar that demonstrates keyword-led statements, function declarations, returns, function-call expressions, integer literals, strings, comments, and keyed table constructors.</p><ul><li><strong>Parser Engines:</strong> <code>ll.grm</code> is provided.</li></ul><h3 id="grammar-parser-languages-galley" tabindex="-1">Grammar Parser (<code>languages/galley</code>) <a class="header-anchor" href="#grammar-parser-languages-galley" aria-label="Permalink to &quot;Grammar Parser (`languages/galley`)&quot;">​</a></h3><p>The self-hosting definition of Galley&#39;s own <code>.grm</code> syntax! This language defines the exact structure of rule definitions, alternatives (<code>|</code>), variable symbols, quoted literals, and <code>@</code> annotations used across the compiler.</p><ul><li><strong>Parser Engines:</strong> Both <code>ll.grm</code> and <code>lr.grm</code> are provided.</li></ul><hr><h2 id="choosing-between-ll-and-lr" tabindex="-1">Choosing Between LL and LR <a class="header-anchor" href="#choosing-between-ll-and-lr" aria-label="Permalink to &quot;Choosing Between LL and LR&quot;">​</a></h2><p>When working with or creating languages in Galley, you can choose between two parsing paradigms:</p><ol><li><p><strong>LL(k) Top-Down Parsing (<code>ll.grm</code>)</strong>:</p><ul><li>Generates recursive-descent parsing tables.</li><li>Ideal for clear, human-readable grammars where rules naturally decompose from top to bottom.</li><li>Requires eliminating left-recursion (e.g. rewrite <code>Expr | Expr &quot;+&quot; Number</code> to right-recursive or iterative form).</li></ul></li><li><p><strong>LR / LALR Bottom-Up Parsing (<code>lr.grm</code>)</strong>:</p><ul><li>Generates deterministic shift-reduce state machines.</li><li>Easily handles left-recursive rules and complex expressions without restructuring.</li><li>Often produces highly optimized state transitions for dense programming languages.</li></ul></li></ol><hr><h2 id="building-and-running-included-languages" tabindex="-1">Building and Running Included Languages <a class="header-anchor" href="#building-and-running-included-languages" aria-label="Permalink to &quot;Building and Running Included Languages&quot;">​</a></h2><p>To compile and benchmark any included language, generate its parse table using <code>uv</code> and invoke <code>zig build</code> from the repository root:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Generate and test the LL parser for standard JSON</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/generate-parser</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --language</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> languages/json</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --parser-type</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> LL</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Doptimize=ReleaseFast</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ll-json</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> languages/json/samples/code-01.json</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Generate and test the LR parser for the Grammar specification itself</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/generate-parser</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --language</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> languages/galley</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --parser-type</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> LR</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Doptimize=ReleaseFast</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lr-galley</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> languages/galley/lr.grm</span></span></code></pre></div>',34)])])}const p=a(i,[["render",l]]);export{h as __pageData,p as default};
